import logging
from dataclasses import dataclass
from dspy.streaming.streaming_listener import StreamListener

logger = logging.getLogger('test.listener')
logger.setLevel(logging.DEBUG)
handler = logging.StreamHandler()
handler.setLevel(logging.DEBUG)
logger.addHandler(handler)

@dataclass
class Delta:
    content: str

@dataclass
class Choice:
    delta: Delta

@dataclass
class Chunk:
    choices: list

def make_chunk(text):
    return Chunk(choices=[Choice(delta=Delta(content=text))])

listener = StreamListener(signature_field_name='answer', debug=True, debug_logger=logger)

for tok in ['[[', ' ## answer ## ]]\n', 'Hello', ' world!', '\n\n', '[[ ## completed', ' ## ]]']:
    result = listener.receive(make_chunk(tok))
    if result:
        print('RESULT:', result)
